<template>
  <div
    v-if="parsedSummary"
    style="
      display: flex;
      flex-direction: column;
      gap: 14px;
      font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif;
    "
  >
    <!-- Hero -->
    <div
      style="
        padding: 18px 20px;
        border-radius: 18px;
        background: linear-gradient(135deg, rgba(10, 132, 255, 0.18), rgba(94, 92, 230, 0.14));
        border: 0.5px solid rgba(120, 160, 255, 0.22);
      "
    >
      <div style="display: flex; align-items: center; gap: 7px; color: #7fb0ff; font-size: 12px; font-weight: 600">
        <span style="width: 8px; height: 8px; border-radius: 50%; background: #0a84ff; box-shadow: 0 0 8px rgba(10, 132, 255, 0.6)"></span>
        {{ isMegaSummary ? '可视化大总结' : '可视化总结' }}
      </div>
      <div style="margin-top: 8px; color: #f5f5f7; font-size: 19px; font-weight: 700; line-height: 1.3">
        {{ parsedSummary.title || `楼层 ${parsedSummary.range.start}-${parsedSummary.range.end}` }}
      </div>
      <div :style="metaGridStyle">
        <span :style="chipStyle" :title="`${parsedSummary.range.start}-${parsedSummary.range.end} 楼`">
          <i class="fa-solid fa-layer-group" :style="chipIconStyle"></i>
          <span :style="chipTextStyle">{{ parsedSummary.range.start }}-{{ parsedSummary.range.end }} 楼</span>
        </span>
        <span v-if="parsedSummary.time" :style="chipStyle" :title="parsedSummary.time">
          <i class="fa-regular fa-clock" :style="chipIconStyle"></i>
          <span :style="chipTextStyle">{{ parsedSummary.time }}</span>
        </span>
        <span v-if="parsedSummary.location" :style="chipStyle" :title="parsedSummary.location">
          <i class="fa-solid fa-location-dot" :style="chipIconStyle"></i>
          <span :style="chipTextStyle">{{ parsedSummary.location }}</span>
        </span>
      </div>
    </div>

    <!-- 剧情概览 -->
    <section v-if="parsedSummary.overview" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('overview')">
        <span :style="groupTitleTextStyle"><i class="fa-solid fa-align-left" :style="groupIconStyle"></i> 剧情概览</span>
        <i :class="isOpen('overview') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('overview')" :style="groupBodyStyle">
        <p :style="textStyle">{{ parsedSummary.overview }}</p>
      </div>
    </section>

    <!-- 重要事件 -->
    <section v-if="parsedSummary.events.length" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('events')">
        <span :style="groupTitleTextStyle"><i class="fa-solid fa-list-check" :style="groupIconStyle"></i> 重要事件</span>
        <i :class="isOpen('events') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('events')" :style="groupBodyStyle">
        <div
          v-for="(event, index) in parsedSummary.events"
          :key="`event-${index}`"
          :style="rowStyle(index)"
        >
          <span :style="numStyle">{{ index + 1 }}</span>
          <span :style="rowTextStyle">{{ event }}</span>
        </div>
      </div>
    </section>

    <!-- 角色状态 -->
    <section v-if="parsedSummary.characters.length" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('characters')">
        <span :style="groupTitleTextStyle"><i class="fa-solid fa-users" :style="groupIconStyle"></i> 角色状态</span>
        <i :class="isOpen('characters') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('characters')" :style="groupBodyStyle">
        <div v-for="(character, index) in parsedSummary.characters" :key="`character-${index}`" :style="subStyle(index)">
          <div :style="subHeadStyle"><i class="fa-solid fa-user" :style="groupIconStyle"></i> {{ character.name || '未知角色' }}</div>
          <div v-if="character.status" :style="kvStyle"><span :style="kStyle">状态</span><span :style="vStyle">{{ character.status }}</span></div>
          <div v-if="character.attitude" :style="kvStyle"><span :style="kStyle">态度</span><span :style="vStyle">{{ character.attitude }}</span></div>
          <div v-if="character.memory" :style="kvStyle"><span :style="kStyle">记忆</span><span :style="vStyle">{{ character.memory }}</span></div>
        </div>
      </div>
    </section>

    <!-- 关系变化 -->
    <section v-if="parsedSummary.relationshipChanges.length" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('relationships')">
        <span :style="groupTitleTextStyle"><i class="fa-solid fa-link" :style="groupIconStyle"></i> 关系变化</span>
        <i :class="isOpen('relationships') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('relationships')" :style="groupBodyStyle">
        <div v-for="(relation, index) in parsedSummary.relationshipChanges" :key="`relation-${index}`" :style="subStyle(index)">
          <div :style="subHeadStyle" style="flex-wrap: wrap">
            <span>{{ relation.from || '未知' }}</span>
            <i class="fa-solid fa-arrow-right-long" style="color: rgba(235, 235, 245, 0.45)"></i>
            <span>{{ relation.to || '未知' }}</span>
          </div>
          <div v-if="relation.change" :style="kvStyle"><span :style="kStyle">变化</span><span :style="vStyle">{{ relation.change }}</span></div>
          <div v-if="relation.reason" :style="kvStyle"><span :style="kStyle">原因</span><span :style="vStyle">{{ relation.reason }}</span></div>
        </div>
      </div>
    </section>

    <!-- 伏笔 -->
    <section v-if="parsedSummary.foreshadowing.length" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('foreshadowing')">
        <span :style="groupTitleTextStyle"><i class="fa-solid fa-puzzle-piece" :style="groupIconStyle"></i> 伏笔 / 线索</span>
        <i :class="isOpen('foreshadowing') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('foreshadowing')" :style="groupBodyStyle">
        <div v-for="(item, index) in parsedSummary.foreshadowing" :key="`foreshadow-${index}`" :style="rowStyle(index)">
          <span :style="bulletStyle('#ff9f0a')"></span>
          <span :style="rowTextStyle">{{ item }}</span>
        </div>
      </div>
    </section>

    <!-- 待跟进 -->
    <section v-if="parsedSummary.todo.length" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('todo')">
        <span :style="groupTitleTextStyle"><i class="fa-regular fa-circle-check" :style="groupIconStyle"></i> 待跟进</span>
        <i :class="isOpen('todo') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('todo')" :style="groupBodyStyle">
        <div v-for="(item, index) in parsedSummary.todo" :key="`todo-${index}`" :style="rowStyle(index)">
          <span :style="bulletStyle('#0a84ff')"></span>
          <span :style="rowTextStyle">{{ item }}</span>
        </div>
      </div>
    </section>

    <!-- 世界书候选 -->
    <section v-if="parsedSummary.worldbookCandidates.length" :style="groupStyle">
      <div :style="groupTitleStyle" @click="toggleSection('worldbook')">
        <span :style="groupTitleTextStyle"><i class="fa-solid fa-book" :style="groupIconStyle"></i> 世界书候选</span>
        <i :class="isOpen('worldbook') ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'" :style="chevronStyle"></i>
      </div>
      <div v-if="isOpen('worldbook')" :style="groupBodyStyle">
        <div v-for="(candidate, index) in parsedSummary.worldbookCandidates" :key="`wb-${index}`" :style="subStyle(index)">
          <div :style="subHeadStyle" style="flex-wrap: wrap">
            <span :style="candidate.enabled ? tagOnStyle : tagOffStyle">{{ candidate.enabled ? '写入' : '跳过' }}</span>
            <span style="flex: 1; min-width: 80px">{{ candidate.title || '未命名' }}</span>
            <span :style="tagTypeStyle">{{ candidate.type }}</span>
          </div>
          <p v-if="candidate.content" :style="textStyle" style="font-size: 13.5px; color: rgba(235, 235, 245, 0.8)">{{ candidate.content }}</p>
        </div>
      </div>
    </section>
  </div>
</template>

<script setup lang="ts">
import { computed, ref } from 'vue';
import type { VisualSummary } from '../types/visual-summary';
import { parseVisualSummary } from '../utils/visual-summary-format';

const props = defineProps<{
  summary: VisualSummary | unknown;
}>();

const parsedSummary = computed(() => parseVisualSummary(props.summary));
const isMegaSummary = computed(() => String(parsedSummary.value?.title || '').includes('大总结'));
const openSections = ref(new Set(['overview', 'events']));

function isOpen(section: string): boolean {
  return openSections.value.has(section);
}

function toggleSection(section: string) {
  const next = new Set(openSections.value);
  if (next.has(section)) {
    next.delete(section);
  } else {
    next.add(section);
  }
  openSections.value = next;
}

// ===== 内联样式（规避 style.css 缓存）=====
const metaGridStyle =
  'margin-top: 12px; display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 8px; align-items: stretch;';
const chipStyle =
  'min-width: 0; min-height: 44px; display: grid; grid-template-columns: auto minmax(0, 1fr); align-items: center; gap: 6px; padding: 7px 9px; border-radius: 18px; background: rgba(255,255,255,0.1); color: rgba(235,235,245,0.85); font-size: 12px; font-weight: 500;';
const chipTextStyle =
  'min-width: 0; overflow: hidden; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; line-height: 1.28; word-break: break-word;';
const chipIconStyle = 'flex: 0 0 auto; font-size: 11px; color: #7fb0ff;';
const groupStyle =
  'border-radius: 16px; background: rgba(44,44,46,0.55); border: 0.5px solid rgba(255,255,255,0.08); overflow: hidden;';
const groupTitleStyle =
  'display: flex; align-items: center; justify-content: space-between; gap: 8px; padding: 13px 16px 9px; color: rgba(235,235,245,0.6); font-size: 12.5px; font-weight: 600; letter-spacing: 0.3px; cursor: pointer; user-select: none;';
const groupTitleTextStyle = 'display: inline-flex; align-items: center; gap: 8px; min-width: 0;';
const groupIconStyle = 'color: #0a84ff; font-size: 12px;';
const chevronStyle = 'flex: 0 0 auto; color: rgba(235,235,245,0.45); font-size: 11px;';
const groupBodyStyle = 'padding: 0 16px 14px;';
const textStyle =
  'margin: 0; color: rgba(235,235,245,0.92); font-size: 14.5px; line-height: 1.62; white-space: pre-wrap; word-break: break-word;';
const rowTextStyle = 'flex: 1; color: rgba(235,235,245,0.92); font-size: 14px; line-height: 1.55;';
const numStyle =
  'flex: 0 0 auto; min-width: 22px; height: 22px; padding: 0 6px; border-radius: 7px; background: rgba(10,132,255,0.18); color: #4ea1ff; font-size: 12px; font-weight: 700; display: inline-flex; align-items: center; justify-content: center;';
const subHeadStyle =
  'display: flex; align-items: center; gap: 8px; color: #f5f5f7; font-size: 14.5px; font-weight: 600; margin-bottom: 8px;';
const kvStyle = 'display: flex; gap: 10px; padding: 4px 0; font-size: 13.5px; line-height: 1.5;';
const kStyle = 'flex: 0 0 auto; min-width: 40px; color: rgba(235,235,245,0.5); font-size: 12.5px;';
const vStyle = 'flex: 1; color: rgba(235,235,245,0.9);';
const tagOnStyle =
  'display: inline-flex; align-items: center; padding: 2px 9px; border-radius: 999px; font-size: 11px; font-weight: 600; background: rgba(48,209,88,0.2); color: #5fe07f;';
const tagOffStyle =
  'display: inline-flex; align-items: center; padding: 2px 9px; border-radius: 999px; font-size: 11px; font-weight: 600; background: rgba(235,235,245,0.14); color: rgba(235,235,245,0.7);';
const tagTypeStyle =
  'display: inline-flex; align-items: center; padding: 2px 9px; border-radius: 999px; font-size: 11px; font-weight: 600; background: rgba(10,132,255,0.18); color: #4ea1ff;';

function rowStyle(index: number): string {
  const border = index === 0 ? '' : 'border-top: 0.5px solid rgba(255,255,255,0.07);';
  return `display: flex; align-items: flex-start; gap: 10px; padding: 9px 0; ${border}`;
}

function subStyle(index: number): string {
  const margin = index === 0 ? '' : 'margin-top: 10px;';
  return `padding: 12px 14px; border-radius: 12px; background: rgba(255,255,255,0.05); ${margin}`;
}

function bulletStyle(color: string): string {
  return `flex: 0 0 auto; width: 7px; height: 7px; margin-top: 7px; border-radius: 50%; background: ${color};`;
}
</script>
