// 工具展开状态管理
const toolExpandedState = ref(new Map<string, boolean>());

export function useToolExpand() {
  const isToolExpanded = (toolKey: string) => {
    return toolExpandedState.value.get(toolKey) || false;
  };

  const toggleToolExpanded = (toolKey: string) => {
    const current = toolExpandedState.value.get(toolKey) || false;
    toolExpandedState.value.set(toolKey, !current);
  };

  const setToolExpanded = (toolKey: string, expanded: boolean) => {
    toolExpandedState.value.set(toolKey, expanded);
  };

  return {
    toolExpandedState,
    isToolExpanded,
    toggleToolExpanded,
    setToolExpanded,
  };
}

// 世界书操作
export function useWorldbook() {
  const availableWorldbooks = ref<string[]>([]);

  const loadAvailableWorldbooks = () => {
    try {
      const tav = (window as any).TavernHelper;
      if (typeof tav?.getWorldbookNames === 'function') {
        availableWorldbooks.value = tav.getWorldbookNames();
        console.log('✅ 已加载世界书列表:', availableWorldbooks.value);
      } else if (typeof tav?.getLorebooks === 'function') {
        availableWorldbooks.value = tav.getLorebooks();
        console.log('✅ 已加载世界书列表 (旧版 API):', availableWorldbooks.value);
      } else {
        availableWorldbooks.value = [];
        console.warn('⚠️ TavernHelper 不可用，世界书功能受限');
      }
    } catch (error) {
      console.error('❌ 加载世界书列表失败:', error);
      availableWorldbooks.value = [];
    }
  };

  const getWorldbookEntries = async (worldbookName: string) => {
    try {
      const tav = (window as any).TavernHelper;
      if (!tav) return [];

      let entries: any[] = [];
      if (typeof tav.getWorldbook === 'function') {
        entries = (await tav.getWorldbook(worldbookName)) || [];
      } else if (typeof tav.getWorldbookEntries === 'function') {
        entries = tav.getWorldbookEntries(worldbookName) || [];
      }
      return entries;
    } catch (error) {
      console.error('❌ 获取世界书条目失败:', error);
      return [];
    }
  };

  const insertWorldbookEntry = async (worldbookName: string, entry: any) => {
    try {
      const tav = (window as any).TavernHelper;
      if (!tav) {
        window.toastr?.warning?.('TavernHelper 不可用');
        return false;
      }

      if (typeof tav.addWorldbookEntry === 'function') {
        await tav.addWorldbookEntry(worldbookName, entry);
        window.toastr?.success?.('已插入世界书');
        return true;
      }
      return false;
    } catch (error) {
      console.error('❌ 插入世界书失败:', error);
      window.toastr?.error?.('插入失败: ' + (error as Error).message);
      return false;
    }
  };

  return {
    availableWorldbooks,
    loadAvailableWorldbooks,
    getWorldbookEntries,
    insertWorldbookEntry,
  };
}

// 角色卡读取
export function useCharacterCard() {
  const getCharacterField = (field: string): string => {
    try {
      const tav = (window as any).TavernHelper;
      if (!tav?.getCharacter) return '';

      const char = tav.getCharacter();
      if (!char) return '';

      return char[field] || '';
    } catch (error) {
      console.error('❌ 读取角色卡失败:', error);
      return '';
    }
  };

  const getFullCharacterInfo = (): string => {
    const fields = ['description', 'personality', 'scenario', 'mes_example'];
    const parts: string[] = [];

    for (const field of fields) {
      const value = getCharacterField(field);
      if (value) {
        parts.push(`【${field}】\n${value}`);
      }
    }

    return parts.join('\n\n');
  };

  return {
    getCharacterField,
    getFullCharacterInfo,
  };
}

// AI 调用封装
export function useAICall() {
  const settingsStore = useSettingsStore();
  const { settings } = storeToRefs(settingsStore);

  interface AICallOptions {
    prompt: string;
    systemPrompt?: string;
    maxTokens?: number;
    onProgress?: (text: string) => void;
    streaming?: boolean;
  }

  const callAI = async (options: AICallOptions): Promise<string> => {
    const { prompt, systemPrompt = '', maxTokens = 2000, onProgress } = options;

    const messages = [
      ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
      { role: 'user', content: prompt },
    ];

    const apiSettings = {
      use_tavern_api: settings.value.use_tavern_api,
      api_endpoint: settings.value.api_endpoint,
      api_key: settings.value.api_key,
      model: settings.value.model,
      max_tokens: maxTokens,
      temperature: settings.value.temperature,
    };

    const result = await callAIWithTavernSupport(messages, apiSettings, {
      onProgress: onProgress ? (p: number) => onProgress(String(p)) : undefined,
    });

    return result;
  };

  return {
    callAI,
    settings,
  };
}

