<template>
  <div :style="rootStyle">
    <!-- 版本信息 -->
    <div :style="heroStyle">
      <div :style="{ display: 'flex', justifyContent: 'center', marginBottom: '14px', color: c.accent }">
        <CatIcon :size="48" color="currentColor" />
      </div>
      <h2 :style="{ margin: '0 0 14px', textAlign: 'center', fontSize: '22px', fontWeight: 700, color: c.title }">
        mzrodyu猫猫的小工具
      </h2>

      <div style="display: flex; flex-wrap: wrap; gap: 10px; justify-content: center; align-items: center">
        <span :style="{ fontSize: '13px', color: c.textSub }">版本 v{{ currentVersion }}</span>
        <button
          :style="[btnBase, btnGhost, (isCheckingUpdate || isForceUpdating) ? btnDisabled : {}]"
          :disabled="isCheckingUpdate || isForceUpdating"
          @click="checkForUpdates"
        >
          <span :style="isCheckingUpdate ? spinStyle : undefined">↻</span>
          {{ isCheckingUpdate ? '检查中...' : '版本检测' }}
        </button>
        <button
          :style="[btnBase, btnPrimary, (isForceUpdating || isCheckingUpdate) ? btnDisabled : {}]"
          :disabled="isForceUpdating || isCheckingUpdate"
          @click="forceUpdate"
        >
          <span :style="isForceUpdating ? spinStyle : undefined">↓</span>
          {{ isForceUpdating ? '更新中...' : '强制更新' }}
        </button>
      </div>

      <!-- 版权声明 -->
      <div :style="copyrightBoxStyle">
        <div :style="{ fontSize: '13px', fontWeight: 600, marginBottom: '8px', color: c.danger }">版权声明</div>
        <div style="display: flex; flex-direction: column; gap: 6px">
          <div v-for="(item, i) in copyright" :key="i" style="display: flex; align-items: center; gap: 8px">
            <span :style="{ width: '7px', height: '7px', borderRadius: '50%', flexShrink: 0, background: item.color }"></span>
            <span :style="{ fontSize: '13px', color: c.text }">{{ item.text }}</span>
          </div>
        </div>
      </div>
    </div>

    <!-- 使用说明 -->
    <div :style="cardStyle">
      <h3 :style="sectionTitleStyle" @click="toggleSection('usageGuide')">
        <span :style="[badgeStyle, { background: c.badgeInfoBg, color: c.badgeInfoText }]">i</span>
        <span style="flex: 1">使用说明</span>
        <span :style="{ fontSize: '12px', color: c.textSub }">{{ expandedSections.usageGuide ? '▲' : '▼' }}</span>
      </h3>
      <div v-show="expandedSections.usageGuide" :style="bodyStyle">
        <!-- eslint-disable-next-line vue/no-v-html -->
        <div class="maomaomz-md" :class="{ 'maomaomz-md-light': isLight }" v-html="renderMarkdown(pluginUsage)"></div>
      </div>
    </div>

    <!-- 更新日志 -->
    <div :style="cardStyle">
      <h3 :style="sectionTitleStyle" @click="toggleSection('changelog')">
        <span :style="[badgeStyle, { background: c.badgeOkBg, color: c.badgeOkText }]">更</span>
        <span style="flex: 1">更新日志</span>
        <span :style="{ fontSize: '12px', color: c.textSub }">{{ expandedSections.changelog ? '▲' : '▼' }}</span>
      </h3>
      <div v-show="expandedSections.changelog" :style="bodyStyle">
        <!-- eslint-disable-next-line vue/no-v-html -->
        <div class="maomaomz-md" :class="{ 'maomaomz-md-light': isLight }" v-html="renderMarkdown(pluginChangelog)"></div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, onUnmounted, reactive, ref } from 'vue';
import { CURRENT_VERSION, manualCheckUpdates, performExtensionUpdate, reloadHostPage } from '../versionCheck';
import CatIcon from './CatIcon.vue';

const currentVersion = CURRENT_VERSION;
const isCheckingUpdate = ref(false);
const isForceUpdating = ref(false);

// 内置使用说明 / 更新日志（不再依赖任何后端）
const BUILTIN_USAGE = `# 使用说明

猫猫的小工具是一个 SillyTavern 扩展，提供记忆总结、状态栏生成、写卡工具箱、MVU 变量框架等功能。

## 快速开始
1. 在「设置 → AI 设置」中配置 API（或直接复用酒馆已配置的 API）。
2. 「记忆管理」可手动 / 自动总结聊天并写入世界书。
3. 「状态栏」可快速生成角色状态栏代码。
4. 「工具箱」提供角色卡、NPC、世界书条目、开场白等生成工具。
5. 「MVU」用于生成变量结构、COT 提示词与状态栏模板（默认隐藏，可在界面偏好开启）。

## 小贴士
- 不需要的功能模块可在「界面偏好 → 功能模块」中关闭。
- 有问题或想二改，@ 一下作者就好。`;

const BUILTIN_CHANGELOG = `# 更新日志

版本更新通过「版本检测 / 强制更新」从发布仓库获取，点击上方按钮即可检查并更新到最新版本。`;

const pluginUsage = ref(BUILTIN_USAGE);
const pluginChangelog = ref(BUILTIN_CHANGELOG);

// 是否浅色模式（响应式，跟随面板的 maomaomz-light class）
const isLight = ref(false);
let observer: MutationObserver | null = null;

const detectLight = () => {
  const panel = document.getElementById('memoryManagementPanel');
  isLight.value = !!panel?.classList.contains('maomaomz-light');
};

const copyright = [
  { text: '本脚本发布在类脑', color: '#4a9eff' },
  { text: '二改二创随意', color: '#30d158' },
  { text: '使用或二改时 @ 一下作者就好', color: '#4a9eff' },
];

// 配色（根据深/浅色返回对应颜色集）
const c = computed(() => {
  if (isLight.value) {
    return {
      title: '#1c1c1e',
      text: '#1c1c1e',
      textSub: 'rgba(60, 60, 67, 0.6)',
      accent: '#007aff',
      danger: '#ff3b30',
      cardBg: '#ffffff',
      cardBorder: 'rgba(60, 60, 67, 0.16)',
      heroBg: 'linear-gradient(135deg, #dbeafe 0%, #eff6ff 100%)',
      heroBorder: 'rgba(0, 122, 255, 0.18)',
      copyrightBg: 'rgba(255, 59, 48, 0.06)',
      copyrightBorder: 'rgba(255, 59, 48, 0.22)',
      badgeInfoBg: 'rgba(0, 122, 255, 0.16)',
      badgeInfoText: '#0066cc',
      badgeOkBg: 'rgba(40, 167, 69, 0.18)',
      badgeOkText: '#1f8a3b',
      ghostBg: '#ffffff',
      ghostBorder: 'rgba(60, 60, 67, 0.2)',
    };
  }
  return {
    title: '#ffffff',
    text: '#e8e8ea',
    textSub: 'rgba(235, 235, 245, 0.6)',
    accent: '#0a84ff',
    danger: '#ff453a',
    cardBg: 'rgba(44, 44, 46, 0.9)',
    cardBorder: 'rgba(84, 84, 88, 0.5)',
    heroBg: 'linear-gradient(135deg, #2a3a4a 0%, #1f2a36 100%)',
    heroBorder: 'rgba(84, 84, 88, 0.5)',
    copyrightBg: 'rgba(255, 69, 58, 0.1)',
    copyrightBorder: 'rgba(255, 69, 58, 0.28)',
    badgeInfoBg: 'rgba(10, 132, 255, 0.22)',
    badgeInfoText: '#64d2ff',
    badgeOkBg: 'rgba(48, 209, 88, 0.22)',
    badgeOkText: '#30d158',
    ghostBg: 'rgba(118, 118, 128, 0.24)',
    ghostBorder: 'rgba(84, 84, 88, 0.5)',
  };
});

// ===== 内联样式（不依赖 scoped/style.css，规避缓存导致的样式丢失）=====
const rootStyle = computed(() => ({ padding: '22px', maxWidth: '900px', margin: '0 auto' }));

const heroStyle = computed(() => ({
  background: c.value.heroBg,
  border: `1px solid ${c.value.heroBorder}`,
  borderRadius: '20px',
  padding: '28px 24px',
  marginBottom: '18px',
}));

const cardStyle = computed(() => ({
  background: c.value.cardBg,
  border: `0.5px solid ${c.value.cardBorder}`,
  borderRadius: '18px',
  padding: '20px 22px',
  marginBottom: '16px',
}));

const sectionTitleStyle = computed(() => ({
  margin: '0',
  fontSize: '17px',
  fontWeight: 700,
  color: c.value.title,
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  cursor: 'pointer',
  userSelect: 'none' as const,
}));

const badgeStyle = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: '22px',
  height: '22px',
  borderRadius: '6px',
  fontSize: '12px',
  fontWeight: 700,
  lineHeight: '1',
  flexShrink: 0,
};

const bodyStyle = computed(() => ({
  marginTop: '14px',
  fontSize: '14px',
  lineHeight: '1.8',
  color: c.value.text,
}));

const copyrightBoxStyle = computed(() => ({
  marginTop: '18px',
  background: c.value.copyrightBg,
  border: `1.5px solid ${c.value.copyrightBorder}`,
  borderRadius: '14px',
  padding: '14px 16px',
}));

const btnBase = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '6px',
  padding: '8px 16px',
  borderRadius: '999px',
  fontSize: '13px',
  fontWeight: 600,
  cursor: 'pointer',
  transition: 'all 0.18s ease',
};

const btnGhost = computed(() => ({
  background: c.value.ghostBg,
  border: `1px solid ${c.value.ghostBorder}`,
  color: c.value.title,
}));

const btnPrimary = computed(() => ({
  background: 'var(--maomaomz-theme-color, #0a84ff)',
  border: '1px solid var(--maomaomz-theme-color, #0a84ff)',
  color: '#ffffff',
}));

const btnDisabled = { opacity: 0.6, cursor: 'not-allowed' };

const spinStyle = { display: 'inline-block', animation: 'maomaomzSpin 1s linear infinite' };

const expandedSections = reactive({
  usageGuide: false,
  changelog: false,
});

const toggleSection = (section: keyof typeof expandedSections) => {
  expandedSections[section] = !expandedSections[section];
};

const checkForUpdates = async () => {
  if (isCheckingUpdate.value) return;
  isCheckingUpdate.value = true;
  try {
    await manualCheckUpdates();
  } catch (error) {
    console.error('❌ 检查更新失败:', error);
  } finally {
    isCheckingUpdate.value = false;
  }
};

const forceUpdate = async () => {
  if (isForceUpdating.value) return;
  isForceUpdating.value = true;
  try {
    const result = await performExtensionUpdate();
    if (result.success) {
      window.toastr?.success('✅ 更新成功！3秒后刷新页面...', '完成');
      setTimeout(() => reloadHostPage(), 3000);
    } else {
      window.toastr?.warning(
        `⚠️ 自动更新失败，请手动更新后刷新页面\n\n${result.error || '未知错误'}`,
        '请手动更新',
        { timeOut: 0, closeButton: true },
      );
    }
  } catch (error) {
    console.error('❌ 强制更新失败:', error);
    window.toastr?.error('❌ 更新失败，请查看控制台', '错误');
  } finally {
    isForceUpdating.value = false;
  }
};

const loadPluginInfo = async () => {
  // 使用说明 / 更新日志已内置，无需请求后端
  pluginUsage.value = BUILTIN_USAGE;
  pluginChangelog.value = BUILTIN_CHANGELOG;
};

// 简单的 Markdown 渲染函数
const renderMarkdown = (text: string): string => {
  if (!text) return '';
  let html = text;
  html = html
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
  html = html.replace(/^&gt; (.+)$/gm, '<blockquote-line>$1</blockquote-line>');
  html = html.replace(/(<blockquote-line>[\s\S]+?<\/blockquote-line>\n?)+/g, match => {
    const content = match.replace(/<blockquote-line>/g, '').replace(/<\/blockquote-line>\n?/g, '<br>');
    return `<blockquote>${content}</blockquote>`;
  });
  html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
  html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
  html = html.replace(/`([^`]+)`/g, '<code>$1</code>');
  html = html.replace(/^- (.+)$/gm, '<li>$1</li>');
  html = html.replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>');
  html = html.replace(/^\d+\. (.+)$/gm, '<li>$1</li>');
  html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank">$1</a>');
  html = html.replace(/^---$/gm, '<hr>');
  html = html.replace(/\n\n/g, '<br><br>');
  html = html.replace(/\n/g, '<br>');
  return html;
};

onMounted(() => {
  detectLight();
  const panel = document.getElementById('memoryManagementPanel');
  if (panel) {
    observer = new MutationObserver(detectLight);
    observer.observe(panel, { attributes: true, attributeFilter: ['class'] });
  }
  loadPluginInfo();
});

onUnmounted(() => {
  observer?.disconnect();
  observer = null;
});
</script>

