<script setup lang="ts">
import { computed, onMounted, ref } from 'vue';

type SourceKey = 'primary' | 'additional' | 'global' | 'chat';

interface SourceStats {
  c: number;
  s: number;
  v: number;
  books: string[];
}

interface LorebookStats {
  c: number;
  s: number;
  v: number;
  t: number;
  source: SourceKey;
}

interface TokenStats {
  characterName: string;
  characterCardTokens: number;
  totalConstantTokens: number;
  totalSelectiveTokens: number;
  totalVectorizedTokens: number;
  lorebookTokens: number;
  chatTokens: number;
  // 新增：预设相关
  systemPromptTokens: number;
  personaTokens: number;
  extensionTokens: number;
  totalTokens: number;
  // 真实总量：通过 dry-run 捕获酒馆实际组装、即将发送给模型的完整提示词
  accurateTotalTokens: number | null;
  accuratePromptMessages: number;
  bySource: Record<SourceKey, SourceStats>;
  byLorebook: Record<string, LorebookStats>;
}

const loading = ref(false);
const error = ref<string | null>(null);
const stats = ref<TokenStats | null>(null);
const lastUpdated = ref<number | null>(null);

const envReady = computed(() => {
  const w = window as any;
  return !!(w.SillyTavern && w.TavernHelper);
});

const sourceOrder: SourceKey[] = ['primary', 'additional', 'global', 'chat'];

const sourceLabels: Record<SourceKey, string> = {
  primary: '主书',
  additional: '附加',
  global: '全局',
  chat: '聊天',
};

const lorebookList = computed(() => {
  if (!stats.value) return [] as Array<LorebookStats & { name: string }>;
  return Object.entries(stats.value.byLorebook)
    .map(([name, s]: [string, LorebookStats]) => ({ name, ...s }))
    .sort((a, b) => b.t - a.t);
});

const lastUpdatedText = computed(() => {
  if (!lastUpdated.value) return '尚未计算';
  const date = new Date(lastUpdated.value);
  const hh = String(date.getHours()).padStart(2, '0');
  const mm = String(date.getMinutes()).padStart(2, '0');
  return `${hh}:${mm}`;
});

function formatNumber(n: number): string {
  return n.toLocaleString();
}

function short(n: number): string {
  if (n >= 10000) return `${(n / 1000).toFixed(0)}k`;
  if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
  return n.toString();
}

function percent(part: number, total: number): string {
  if (!total || total <= 0) return '0.0';
  return ((part / total) * 100).toFixed(1);
}

function sourceTotal(s: SourceStats): number {
  return s.c + s.s + s.v;
}

// 缓存 tokenizer 函数引用
let cachedTokenizer: ((text: string) => number) | null = null;

/**
 * 酒馆作为第三方扩展暴露给插件的 window.SillyTavern 只有 { libs, getContext }，
 * 真正的 eventSource / generate / eventTypes / getTokenCount(Async) 等 API
 * 全部在 SillyTavern.getContext() 返回的对象里，不在 SillyTavern 本身上。
 * （这与 JS-Slash-Runner 之类跑在 iframe 里、直接 import 模块的插件不同，那种能拿到裸函数。）
 */
function getSillyTavernContext(): any | null {
  try {
    const wins = [window, (window as any).parent, (window as any).top, (window as any).opener].filter(Boolean);
    for (const w of wins) {
      try {
        const ctx = (w as any)?.SillyTavern?.getContext?.();
        if (ctx) return ctx;
      } catch {
        // 跨域访问可能会失败，忽略
      }
    }
  } catch {
    /* ignore */
  }
  return null;
}

// 查找可用的 tokenizer
function findTokenizer(): ((text: string) => number) | null {
  if (cachedTokenizer) return cachedTokenizer;

  try {
    const ctx = getSillyTavernContext();
    if (typeof ctx?.getTokenCount === 'function') {
      console.log('[TokenStats] 找到 tokenizer: SillyTavern.getContext().getTokenCount');
      cachedTokenizer = (text: string) => ctx.getTokenCount(text);
      return cachedTokenizer;
    }

    // 兜底：按优先级尝试不同的访问方式（旧环境/其他插件可能直接挂在 window 上）
    const contexts = [window, window.parent, window.top, (window as any).opener].filter(Boolean);
    for (const w of contexts) {
      try {
        const c = w as any;
        if (c?.TavernHelper?.getTokenCount) {
          console.log('[TokenStats] 找到 tokenizer: TavernHelper.getTokenCount');
          cachedTokenizer = (text: string) => c.TavernHelper.getTokenCount(text);
          return cachedTokenizer;
        }
        if (typeof c?.getTokenCount === 'function') {
          console.log('[TokenStats] 找到 tokenizer: 全局 getTokenCount');
          cachedTokenizer = c.getTokenCount;
          return cachedTokenizer;
        }
      } catch {
        // 跨域访问可能会失败，忽略
      }
    }
  } catch (e) {
    console.warn('[TokenStats] 查找 tokenizer 失败:', e);
  }

  console.warn('[TokenStats] 未找到可用的 tokenizer，将使用估算');
  return null;
}

// 使用 SillyTavern.getTokenCount 计算 token
function getTokenCount(text: string | null | undefined): number {
  if (!text || typeof text !== 'string') return 0;

  const tokenizer = findTokenizer();
  if (tokenizer) {
    try {
      return tokenizer(text);
    } catch (e) {
      console.warn('[TokenStats] tokenizer 调用失败:', e);
    }
  }

  // 降级：粗略估算
  const chineseChars = (text.match(/[\u4e00-\u9fff]/g) || []).length;
  const otherChars = text.length - chineseChars;
  return Math.ceil(chineseChars / 1.5 + otherChars / 4);
}

// 异步精确分词（优先用酒馆官方异步分词器，回退到同步）
async function getTokenCountAsync(text: string | null | undefined): Promise<number> {
  if (!text || typeof text !== 'string') return 0;
  try {
    const ctx = getSillyTavernContext();
    if (typeof ctx?.getTokenCountAsync === 'function') {
      const n = await ctx.getTokenCountAsync(text);
      if (typeof n === 'number' && !Number.isNaN(n)) return n;
    }
  } catch {
    /* ignore */
  }
  return getTokenCount(text);
}

/**
 * 复刻酒馆 ChatCompletion.squashSystemMessages() 的合并规则：
 * 把连续、没有单独 name 的 system 角色消息合并成一条。
 * 真实发送前酒馆只在 dryRun===false 且用户开启「压缩系统消息」时才做这个合并，
 * 我们拿到的 dry-run 数据永远是合并前的碎片化版本，必须自己补上，
 * 否则统计出来的消息条数会远多于「提示词查看器」显示的真实条数。
 *
 * 注：酒馆原版还会跳过 identifier 为 newMainChat/newChat/groupNudge 的消息不合并，
 * 但 CHAT_COMPLETION_PROMPT_READY 事件拿到的消息数组已经被 getChat() 精简，不带 identifier，
 * 这几种情况通常只出现在空聊天/群聊场景，日常单角色场景基本不受影响，此处做近似处理。
 */
function squashSystemMessagesLike(messages: any[]): any[] {
  const squashed: any[] = [];
  let last: any = null;
  const shouldSquash = (m: any) => m?.role === 'system' && !m?.name;
  for (const msg of messages) {
    // 强制跳过空的 system 消息（酒馆原逻辑同样跳过）
    if (msg?.role === 'system' && !msg?.content) continue;
    if (shouldSquash(msg)) {
      if (last && shouldSquash(last)) {
        last.content = `${last.content || ''}\n${msg.content || ''}`;
      } else {
        const clone = { ...msg };
        squashed.push(clone);
        last = clone;
      }
    } else {
      squashed.push(msg);
      last = msg;
    }
  }
  return squashed;
}

/**
 * 粗略判断酒馆当前是否正在进行一次真实生成。
 * 如果真实生成正在进行，此时再触发一次 dryRun 生成可能会与其抢占 abortController / UI 状态，
 * 所以宁可跳过精确统计、直接回退到估算值。
 */
function isRealGenerationInProgress(): boolean {
  try {
    const ctx = getSillyTavernContext();
    if (ctx?.streamingProcessor && !ctx.streamingProcessor.isFinished) return true;
    const stopBtn = document.getElementById('mes_stop');
    if (stopBtn && (stopBtn as HTMLElement).offsetParent !== null) return true;
  } catch {
    /* ignore */
  }
  return false;
}

/**
 * 通过 dry-run 捕获酒馆实际组装、即将发送给模型的完整提示词，
 * 然后用酒馆官方分词器逐条计数，得到精确总量。
 *
 * 原理：调用 SillyTavern.generate('normal', {}, true) 触发一次
 * dryRun 生成 —— 酒馆会完整走一遍 WI 激活/宏替换/预设组装等流程，但不会真的把请求发给模型。
 * 组装完成后，酒馆会依次派发：
 *   - GENERATE_AFTER_COMBINE_PROMPTS（文本补全，携带 { prompt: string, dryRun }）
 *   - CHAT_COMPLETION_PROMPT_READY（聊天补全，携带 { chat: SendingMessage[], dryRun }，在 prepareOpenAIMessages 内部触发）
 *   - GENERATE_AFTER_DATA（两种 API 都会触发，携带 (generate_data, dryRun)；generate_data.prompt
 *     对聊天补全是消息数组，对文本补全是字符串——是最终兜底、最可靠的一道捕获点）
 * 只要拿到其中任意一个事件的数据就立即停止监听。
 */
async function captureAccuratePromptTokens(): Promise<{ tokens: number; messages: number } | null> {
  const st = getSillyTavernContext();
  if (!st?.eventSource || !st?.eventTypes || typeof st.generate !== 'function') {
    console.warn('[TokenStats] 无 eventSource/generate（getContext() 拿不到完整 API），跳过精确统计');
    return null;
  }

  if (isRealGenerationInProgress()) {
    console.warn('[TokenStats] 检测到真实生成正在进行，跳过精确统计以避免冲突');
    return null;
  }

  // 🔑 关键：酒馆的 GENERATE_AFTER_COMBINE_PROMPTS 事件不管当前是不是聊天补全都会触发——
  // 酒馆内部对 main_api === 'openai' 时 getCombinedPrompt() 直接短路返回空字符串 ''，
  // 且这个事件在 CHAT_COMPLETION_PROMPT_READY 之前就已经派发。如果两个事件都注册监听，
  // 「谁先到就用谁」的写法会被这个空字符串抢先 resolve 成 0 tokens，导致看似"拿到数据"
  // 但其实是空的，外层 tokens > 0 判断失败又退回估算值——这是上一版真正没修好的原因。
  // 因此必须先按 API 类型分流，只监听对应类型会给出真实数据的事件，不能两个都监听。
  const isChatCompletion = st.mainApi === 'openai';
  console.log('[TokenStats] dry-run 捕获：当前 API =', st.mainApi, '(聊天补全:', isChatCompletion, ')');

  const ev = st.eventTypes;
  const READY = ev.CHAT_COMPLETION_PROMPT_READY;
  const COMBINED = ev.GENERATE_AFTER_COMBINE_PROMPTS;
  const AFTER_DATA = ev.GENERATE_AFTER_DATA;

  return await new Promise(resolve => {
    let settled = false;
    const cleanupFns: Array<() => void> = [];

    const cleanup = () => {
      cleanupFns.forEach(fn => {
        try {
          fn();
        } catch {
          /* ignore */
        }
      });
    };

    const finish = async (payload: { chat?: any[]; prompt?: string | any[] } | null) => {
      if (settled) return;

      // 先判断数据是否有效，避免空字符串等无效 payload 抢先把还在等待其他事件的监听器清掉
      if (payload) {
        const chatMessages = Array.isArray(payload.chat)
          ? payload.chat
          : Array.isArray(payload.prompt)
            ? payload.prompt
            : null;
        const hasValidPrompt = typeof payload.prompt === 'string' && payload.prompt.length > 0;

        if (!chatMessages && !hasValidPrompt) {
          console.warn('[TokenStats] 捕获到的 payload 没有有效内容，忽略并继续等待其他事件:', payload);
          return; // 不 settle、不 cleanup，让其他仍在监听的事件继续有机会拿到真正的数据
        }
      }

      settled = true;
      cleanup();

      if (!payload) {
        resolve(null);
        return;
      }
      try {
        let chatMessages = Array.isArray(payload.chat)
          ? payload.chat
          : Array.isArray(payload.prompt)
            ? payload.prompt
            : null;

        if (chatMessages) {
          // 🔑 关键：真实发送前，酒馆会在用户开启「压缩系统消息」（squash_system_messages）
          // 时把连续、没有单独 name 的 system 角色消息合并成一条（squashSystemMessages()）。
          // 但这个合并只在 dryRun === false 时执行，我们用 dryRun 拿到的是
          // "合并前"的碎片化消息数组——条数会远多于真实发送的条数，必须手动补上同样的合并逻辑
          // （只在用户确实开启了该设置时才合并，否则真实发送时也不会合并，不能瞎合并）。
          const squashEnabled = !!st?.chatCompletionSettings?.squash_system_messages;
          if (squashEnabled) {
            chatMessages = squashSystemMessagesLike(chatMessages);
          }

          // 聊天补全（OpenAI 类）：{role, content} 数组，合并后逐条重新分词
          let total = 0;
          for (const msg of chatMessages) {
            const content = typeof msg?.content === 'string' ? msg.content : '';
            total += await getTokenCountAsync(content);
            // 每条消息有角色/分隔开销，酒馆按 ~4 token/消息估算包装开销
            total += 4;
          }
          total += 3; // 对话整体收尾开销
          console.log('[TokenStats] dry-run 精确捕获成功（聊天补全）：', chatMessages.length, '条消息，', total, 'tokens');
          resolve({ tokens: total, messages: chatMessages.length });
        } else if (typeof payload.prompt === 'string') {
          // 文本补全：prompt 是一整段字符串
          const total = await getTokenCountAsync(payload.prompt);
          console.log('[TokenStats] dry-run 精确捕获成功（文本补全）：', total, 'tokens');
          resolve({ tokens: total, messages: 0 });
        } else {
          resolve(null);
        }
      } catch (e) {
        console.warn('[TokenStats] 精确统计计数失败:', e);
        resolve(null);
      }
    };

    const onReady = (data: any) => {
      // 只接受 dryRun 的数据，避免误吞真实生成
      if (data?.dryRun === false) return;
      void finish({ chat: data?.chat });
    };
    const onCombined = (data: any) => {
      if (data?.dryRun === false) return;
      void finish({ prompt: data?.prompt });
    };
    const onAfterData = (generateData: any, dryRun: boolean) => {
      if (dryRun === false) return;
      void finish({ prompt: generateData?.prompt });
    };

    try {
      // 按 API 类型分流注册，避免聊天补全下 COMBINED 事件的空字符串抢先误判
      if (isChatCompletion) {
        if (READY) {
          st.eventSource.on(READY, onReady);
          cleanupFns.push(() => st.eventSource.removeListener(READY, onReady));
        }
      } else {
        if (COMBINED) {
          st.eventSource.on(COMBINED, onCombined);
          cleanupFns.push(() => st.eventSource.removeListener(COMBINED, onCombined));
        }
      }
      // GENERATE_AFTER_DATA 两种 API 都会触发，作为兜底
      if (AFTER_DATA) {
        st.eventSource.on(AFTER_DATA, onAfterData);
        cleanupFns.push(() => st.eventSource.removeListener(AFTER_DATA, onAfterData));
      }
    } catch (e) {
      console.warn('[TokenStats] 注册事件失败:', e);
      void finish(null);
      return;
    }

    // 触发 dry-run 生成：SillyTavern.generate('normal', {}, true) 中第三个参数为 dryRun
    try {
      const result = st.generate('normal', {}, true);
      if (result && typeof result.then === 'function') {
        result.catch((e: unknown) => {
          console.warn('[TokenStats] dry-run 生成 Promise 被拒绝（忽略，若事件已触发不影响结果）:', e);
        });
      }
    } catch (e) {
      console.warn('[TokenStats] dry-run 触发失败:', e);
      void finish(null);
      return;
    }

    // 超时保护：拿不到就放弃，避免一直 loading（放宽到 15 秒，容纳较大世界书的扫描耗时）
    setTimeout(() => {
      if (!settled) {
        console.warn('[TokenStats] dry-run 精确统计超时（15s），回退到估算值');
      }
      void finish(null);
    }, 15000);
  });
}

function collectPresetPromptTexts(st: any, tav: any): { texts: string[]; details: string } {
  const texts: string[] = [];
  const seen = new Set<string>(); // 避免重复统计
  let presetCount = 0;

  const pushText = (value: unknown, source: string) => {
    if (typeof value !== 'string') return false;
    const trimmed = value.trim();
    if (trimmed && !seen.has(trimmed)) {
      seen.add(trimmed);
      texts.push(value);
      return true;
    }
    return false;
  };

  // 只统计当前预设中启用的提示词
  if (tav && typeof tav.getPreset === 'function') {
    try {
      const preset = tav.getPreset('in_use');
      if (preset && Array.isArray(preset.prompts)) {
        for (const prompt of preset.prompts) {
          // 只统计启用的、有内容的、非占位符的提示词
          if (prompt?.content && prompt.enabled !== false && !prompt.marker) {
            if (pushText(prompt.content, 'preset')) {
              presetCount++;
            }
          }
        }
      }
    } catch (e) {
      console.warn('[TokenStats] 获取预设失败:', e);
    }
  }

  const details = `预设:${presetCount}`;
  return { texts, details };
}

async function calculateTokenStats(): Promise<void> {
  if (!envReady.value) {
    error.value = '未检测到 SillyTavern / TavernHelper 环境，无法计算 Token。';
    return;
  }

  loading.value = true;
  error.value = null;

  const w = window as any;
  const st = w.SillyTavern;
  const tav = w.TavernHelper;

  const emptySource = (): SourceStats => ({ c: 0, s: 0, v: 0, books: [] });

  const local: TokenStats = {
    characterName: '(未检测到角色)',
    characterCardTokens: 0,
    totalConstantTokens: 0,
    totalSelectiveTokens: 0,
    totalVectorizedTokens: 0,
    lorebookTokens: 0,
    chatTokens: 0,
    // 新增：预设相关
    systemPromptTokens: 0,
    personaTokens: 0,
    extensionTokens: 0,
    totalTokens: 0,
    accurateTotalTokens: null,
    accuratePromptMessages: 0,
    bySource: {
      primary: emptySource(),
      additional: emptySource(),
      global: emptySource(),
      chat: emptySource(),
    },
    byLorebook: {},
  };

  try {
    // 1. 角色卡
    let characterTokensComputed = false;

    // 1.1 优先使用 TavernHelper.getCharData('current')
    if (tav && typeof tav.getCharData === 'function') {
      try {
        const charData = tav.getCharData('current');
        if (charData) {
          console.log('[TokenStats] 使用 TavernHelper.getCharData("current") 获取到角色:', charData.name);
          local.characterName = charData.name || '(未命名角色)';
          // 统计所有角色卡字段
          const fields: string[] = [];
          // V1 字段
          if (charData.description) fields.push(charData.description);
          if (charData.personality) fields.push(charData.personality);
          if (charData.scenario) fields.push(charData.scenario);
          if (charData.first_mes) fields.push(charData.first_mes);
          if (charData.mes_example) fields.push(charData.mes_example);
          if (charData.creatorcomment) fields.push(charData.creatorcomment);
          // V2 字段 (data 对象)
          const v2 = charData.data;
          if (v2) {
            if (v2.system_prompt) fields.push(v2.system_prompt);
            if (v2.post_history_instructions) fields.push(v2.post_history_instructions);
            if (v2.creator_notes) fields.push(v2.creator_notes);
            if (Array.isArray(v2.alternate_greetings)) {
              fields.push(...v2.alternate_greetings.filter(Boolean));
            }
            // 深度提示词
            if (v2.extensions?.depth_prompt?.prompt) {
              fields.push(v2.extensions.depth_prompt.prompt);
            }
          }
          local.characterCardTokens = getTokenCount(fields.join('\n'));
          characterTokensComputed = local.characterCardTokens > 0;
        } else {
          console.log('[TokenStats] TavernHelper.getCharData("current") 返回空');
        }
      } catch (e) {
        console.warn('TavernHelper.getCharData("current") 调用失败:', e);
      }
    }

    // 1.2 降级：直接使用 SillyTavern.characters / groups
    if (!characterTokensComputed && st && Array.isArray(st.characters) && st.characters.length > 0) {
      const charId = (st as any).characterId;
      let ch: any = null;

      // characterId 可能是数字索引，也可能是字符串
      if (typeof charId === 'number' && st.characters[charId]) {
        ch = st.characters[charId];
      } else if (typeof charId === 'string') {
        // 尝试作为数字索引
        const numId = parseInt(charId, 10);
        if (!isNaN(numId) && st.characters[numId]) {
          ch = st.characters[numId];
        }
      }

      // 如果还没找到，取第一个角色（当前聊天的角色）
      if (!ch && st.characters.length > 0) {
        // 尝试用 name2（当前角色名）来匹配
        const name2 = (st as any).name2;
        if (name2) {
          ch = st.characters.find((c: any) => c.name === name2);
        }
        // 最后兜底：取第一个
        if (!ch) {
          ch = st.characters[0];
        }
      }

      if (ch) {
        console.log('[TokenStats] 使用 SillyTavern.characters 获取角色:', ch.name);
        local.characterName = ch.name || '(未命名角色)';
        // 统计所有角色卡字段
        const fields: string[] = [];
        // V1 字段
        if (ch.description) fields.push(ch.description);
        if (ch.personality) fields.push(ch.personality);
        if (ch.scenario) fields.push(ch.scenario);
        if (ch.first_mes) fields.push(ch.first_mes);
        if (ch.mes_example) fields.push(ch.mes_example);
        if (ch.creatorcomment) fields.push(ch.creatorcomment);
        // V2 字段 (data 对象)
        const v2 = ch.data;
        if (v2) {
          if (v2.system_prompt) fields.push(v2.system_prompt);
          if (v2.post_history_instructions) fields.push(v2.post_history_instructions);
          if (v2.creator_notes) fields.push(v2.creator_notes);
          if (Array.isArray(v2.alternate_greetings)) {
            fields.push(...v2.alternate_greetings.filter(Boolean));
          }
          // 深度提示词
          if (v2.extensions?.depth_prompt?.prompt) {
            fields.push(v2.extensions.depth_prompt.prompt);
          }
        }
        local.characterCardTokens = getTokenCount(fields.join('\n'));
        characterTokensComputed = local.characterCardTokens > 0;
      }
    }

    if (!characterTokensComputed && st && (st as any).groupId && Array.isArray((st as any).groups)) {
      const groupId = (st as any).groupId;
      const groups = (st as any).groups as any[];
      const group = groups.find((g: any) => String(g.id) === String(groupId));
      if (group && Array.isArray(group.members) && Array.isArray(st.characters)) {
        console.log('[TokenStats] 使用 SillyTavern.groups 获取群组:', group.name, 'id=', groupId);
        local.characterName = group.name || `群组 ${groupId}`;
        let total = 0;
        for (const avatar of group.members) {
          const member = (st.characters as any[]).find((c: any) => c.avatar === avatar);
          if (member) {
            // 统计所有角色卡字段
            const fields: string[] = [];
            // V1 字段
            if (member.description) fields.push(member.description);
            if (member.personality) fields.push(member.personality);
            if (member.scenario) fields.push(member.scenario);
            if (member.first_mes) fields.push(member.first_mes);
            if (member.mes_example) fields.push(member.mes_example);
            if (member.creatorcomment) fields.push(member.creatorcomment);
            // V2 字段 (data 对象)
            const v2 = member.data;
            if (v2) {
              if (v2.system_prompt) fields.push(v2.system_prompt);
              if (v2.post_history_instructions) fields.push(v2.post_history_instructions);
              if (v2.creator_notes) fields.push(v2.creator_notes);
              if (Array.isArray(v2.alternate_greetings)) {
                fields.push(...v2.alternate_greetings.filter(Boolean));
              }
              if (v2.extensions?.depth_prompt?.prompt) {
                fields.push(v2.extensions.depth_prompt.prompt);
              }
            }
            total += getTokenCount(fields.join('\n'));
          }
        }
        local.characterCardTokens = total;
        characterTokensComputed = local.characterCardTokens > 0;
      }
    }

    // 1.5 预设提示词统计（收集所有系统提示词文本）
    try {
      const { texts: presetTexts, details } = collectPresetPromptTexts(st, tav);
      for (const text of presetTexts) {
        local.systemPromptTokens += getTokenCount(text);
      }
      console.log(
        '[TokenStats] 预设/系统提示词 Tokens:',
        local.systemPromptTokens,
        `(${details}, 共${presetTexts.length}条)`,
      );

      // 用户人设（单独统计）
      if (st?.powerUserSettings?.persona_description) {
        local.personaTokens = getTokenCount(st.powerUserSettings.persona_description);
        console.log('[TokenStats] 用户人设 Tokens:', local.personaTokens);
      }

      // 扩展注入（已在 collectPresetPromptTexts 中处理，这里只记录日志）
      // extensionTokens 保持为 0，因为已经算入 systemPromptTokens
    } catch (e) {
      console.warn('[TokenStats] 获取预设相关 Token 失败:', e);
    }

    // 2. 收集世界书
    const lorebooksToProcess = new Map<string, SourceKey>();

    let settings: any = null;
    if (tav && typeof tav.getLorebookSettings === 'function') {
      try {
        settings = await tav.getLorebookSettings();
      } catch (e) {
        console.warn('getLorebookSettings 调用失败:', e);
      }
    }

    let charLorebooks: { primary: string | null; additional: string[] } = {
      primary: null,
      additional: [],
    };

    if (tav && typeof tav.getCharLorebooks === 'function') {
      try {
        charLorebooks = await tav.getCharLorebooks();
      } catch (e) {
        console.warn('getCharLorebooks 调用失败:', e);
      }
    }

    if (charLorebooks.primary) {
      lorebooksToProcess.set(charLorebooks.primary, 'primary');
    }
    if (Array.isArray(charLorebooks.additional)) {
      for (const name of charLorebooks.additional) {
        if (!lorebooksToProcess.has(name)) {
          lorebooksToProcess.set(name, 'additional');
        }
      }
    }

    if (settings && Array.isArray(settings.selected_global_lorebooks)) {
      for (const name of settings.selected_global_lorebooks as string[]) {
        if (!lorebooksToProcess.has(name)) {
          lorebooksToProcess.set(name, 'global');
        }
      }
    }

    // 注意：不再调用 getOrCreateChatLorebook()，因为它会自动创建聊天世界书
    // "聊天" Token 统计的是对话消息内容，不是聊天世界书

    // 3. 遍历世界书条目
    for (const [bookName, source] of lorebooksToProcess.entries()) {
      local.byLorebook[bookName] = {
        c: 0,
        s: 0,
        v: 0,
        t: 0,
        source,
      };

      let entries: any[] = [];
      if (tav && typeof tav.getLorebookEntries === 'function') {
        try {
          entries = await tav.getLorebookEntries(bookName);
        } catch (e) {
          console.warn(`getLorebookEntries('${bookName}') 失败:`, e);
          continue;
        }
      }

      for (const entry of entries) {
        // 跳过禁用的条目
        if (!entry || !entry.enabled) continue;

        // 计算 Token 数量：优先使用预计算的 tk 字段，与参考脚本保持一致
        const entryTokens =
          typeof (entry as any).tk === 'number' && !Number.isNaN((entry as any).tk)
            ? (entry as any).tk
            : getTokenCount(entry.content);

        // 判断条目类型：使用 entry.type 字符串字段
        let kind: 'c' | 's' | 'v';
        if (entry.type === 'constant') {
          kind = 'c'; // 蓝灯 - constant
        } else if (entry.type === 'vectorized') {
          kind = 'v'; // 向量 - vectorized
        } else {
          kind = 's'; // 绿灯 - selective（默认）
        }

        const bySource = local.bySource[source];
        const byBook = local.byLorebook[bookName];

        if (kind === 'c') {
          local.totalConstantTokens += entryTokens;
          bySource.c += entryTokens;
          byBook.c += entryTokens;
        } else if (kind === 's') {
          local.totalSelectiveTokens += entryTokens;
          bySource.s += entryTokens;
          byBook.s += entryTokens;
        } else {
          local.totalVectorizedTokens += entryTokens;
          bySource.v += entryTokens;
          byBook.v += entryTokens;
        }

        byBook.t += entryTokens;

        if (!bySource.books.includes(bookName)) {
          bySource.books.push(bookName);
        }
      }
    }

    local.lorebookTokens = local.totalConstantTokens + local.totalSelectiveTokens + local.totalVectorizedTokens;

    // 4. 聊天内容（直接统计消息文本）
    try {
      let messages: any[] = [];

      if (st && Array.isArray(st.chat)) {
        messages = st.chat;
      } else if (w.TavernHelper && typeof w.TavernHelper.getChatMessages === 'function') {
        try {
          messages = w.TavernHelper.getChatMessages('0-{{lastMessageId}}') || [];
        } catch (e) {
          console.warn('TavernHelper.getChatMessages 调用失败:', e);
        }
      }

      if (Array.isArray(messages) && messages.length > 0) {
        // 过滤掉隐藏的消息（API不会发送隐藏的消息）
        const visibleMessages = messages.filter((m: any) => !m.is_hidden && !m.hidden && !m.isHidden);
        console.log('[TokenStats] 总消息数:', messages.length, '可见消息数:', visibleMessages.length);

        // 获取上下文限制
        let maxContext = 8192; // 保守默认值
        try {
          // 方法1: TavernHelper.getPreset
          if (tav && typeof tav.getPreset === 'function') {
            const preset = tav.getPreset('in_use');
            if (preset?.settings?.max_context && preset.settings.max_context < 1000000) {
              maxContext = preset.settings.max_context;
            }
          }
          // 方法2: SillyTavern.chatCompletionSettings
          if (maxContext === 8192 && st?.chatCompletionSettings?.max_context_length) {
            const ctx = st.chatCompletionSettings.max_context_length;
            if (ctx > 0 && ctx < 1000000) {
              maxContext = ctx;
            }
          }
          // 方法3: oai_settings
          if (maxContext === 8192 && (st as any)?.oai_settings?.max_context_length) {
            const ctx = (st as any).oai_settings.max_context_length;
            if (ctx > 0 && ctx < 1000000) {
              maxContext = ctx;
            }
          }
        } catch (e) {
          console.warn('[TokenStats] 获取 max_context 失败:', e);
        }

        // 计算非聊天内容占用的 token（预设 + 角色卡 + 蓝灯世界书 + 人设）
        const nonChatTokens =
          local.systemPromptTokens + local.characterCardTokens + local.totalConstantTokens + local.personaTokens;
        const availableForChat = Math.max(0, maxContext - nonChatTokens);
        console.log(
          '[TokenStats] 上下文限制:',
          maxContext,
          '非聊天占用:',
          nonChatTokens,
          '聊天可用:',
          availableForChat,
        );

        // 从最新消息开始向前累计，直到达到可用上下文
        let chatTokens = 0;
        let includedCount = 0;
        for (let i = visibleMessages.length - 1; i >= 0; i--) {
          const m = visibleMessages[i];
          const content = typeof m.mes === 'string' ? m.mes : typeof m.message === 'string' ? m.message : '';
          if (!content) continue;

          const msgTokens = getTokenCount(content);
          if (chatTokens + msgTokens > availableForChat && includedCount > 0) {
            // 超出限制，停止
            break;
          }
          chatTokens += msgTokens;
          includedCount++;
        }

        local.chatTokens = chatTokens;
        console.log(
          '[TokenStats] 聊天内容 Tokens:',
          local.chatTokens,
          `(发送 ${includedCount}/${visibleMessages.length} 条消息)`,
        );
      } else {
        local.chatTokens = 0;
      }
    } catch (e) {
      console.warn('计算聊天内容 Token 失败:', e);
      local.chatTokens = 0;
    }

    // 总 Token = 角色卡 + 蓝灯世界书(constant) + 聊天内容 + 预设相关
    // 注意：只计算蓝灯条目，因为绿灯/向量条目是动态触发的
    local.totalTokens =
      local.characterCardTokens +
      local.totalConstantTokens + // 只用蓝灯，不用全部世界书
      local.chatTokens +
      local.systemPromptTokens +
      local.personaTokens +
      local.extensionTokens;

    // 5. 精确统计：捕获酒馆实际组装的完整提示词
    try {
      const accurate = await captureAccuratePromptTokens();
      if (accurate && accurate.tokens > 0) {
        local.accurateTotalTokens = accurate.tokens;
        local.accuratePromptMessages = accurate.messages;
        console.log(
          '[TokenStats] 精确总 Tokens:',
          accurate.tokens,
          `(${accurate.messages} 条消息)`,
        );
      }
    } catch (e) {
      console.warn('[TokenStats] 精确统计失败，使用估算值:', e);
    }

    stats.value = local;
    lastUpdated.value = Date.now();
  } catch (e) {
    console.error('计算 Token 统计时出错:', e);
    error.value = (e as Error).message || '计算 Token 统计时发生未知错误';
  } finally {
    loading.value = false;
  }
}

function handleRefresh() {
  void calculateTokenStats();
}

onMounted(() => {
  // 默认不自动计算，避免每次打开面板都扫一次。用户手动点击按钮即可。
});
</script>
