export function buildToolGroups(registry: ToolDefinition[] = toolRegistry): ToolGroup[] {
  const result: ToolGroup[] = [];
  for (const key of GROUP_ORDER) {
    const tools = registry.filter(t => t.group === key).sort((a, b) => a.order - b.order);
    if (tools.length > 0) result.push({ ...groupMeta[key], tools });
  }
  return result;
}

export function filterTools(groups: ToolGroup[], activeGroup: ToolGroupKey | 'all', query: string): ToolGroup[] {
  const q = (query || '').trim().toLowerCase();
  const result: ToolGroup[] = [];
  for (const group of groups) {
    if (activeGroup !== 'all' && group.key !== activeGroup) continue;
    const tools = q ? group.tools.filter(t => [t.label, t.desc, ...t.keywords].join(' ').toLowerCase().includes(q)) : group.tools;
    if (tools.length > 0) result.push({ ...group, tools });
  }
  return result;
}

export function resolveToolComponent(id: string): Component | null {
  const def = toolRegistry.find(t => t.id === id);
  return def ? def.component : null;
}

export function getToolDefinition(id: string): ToolDefinition | null {
  return toolRegistry.find(t => t.id === id) || null;
}
